@startuml

skinparam packageStyle rectangle
skinparam shadowing false

package "Task" {
  package "«AGGREGATE»" as TaskAggregate {
    class "Task" as TaskClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "UserStory" {
  package "«AGGREGATE»" as UserStoryAggregate {
    class "UserStory" as UserStoryClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "Sprint" {
  package "«AGGREGATE»" as SprintAggregate {
    class "Sprint" as SprintClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "Typology" {
  package "«AGGREGATE»" as TypologyAggregate {
    class "Typology" as TypologyClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "Project" {
  package "«AGGREGATE»" as ProjectAggregate {
    class "Project" as ProjectClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
    class "Resource" as ResourceInProject {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "ProfileRequest" {
  package "«AGGREGATE»" as ProfileRequestAggregate {
    class "ProfileRequest" as ProfileRequestClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "Profile" {
  package "«AGGREGATE»" as ProfileAggregate {
    class "Profile" as ProfileClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "Resource" {
  package "«AGGREGATE»" as ResourceAggregate {
    class "Resource" as ResourceClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

package "User" {
  package "«AGGREGATE»" as UserAggregate {
    class "User" as UserClass {
      «AGGREGATE ROOT»
      «ENTITY»
    }
  }
}

SprintClass --> UserStoryClass : " "
SprintClass -down-> ProjectClass : " "
TaskClass -down-> SprintClass : " "
TaskClass -right-> ResourceInProject : " "
ProfileRequestClass -up-> TypologyClass : " "
ProfileRequestClass -down-> UserClass : " "
ProfileClass -down-> UserClass : " "
ProfileClass -right-> ResourceInProject : " "
ResourceClass --> UserClass : " "

@enduml
